   171→  public static Map<String, OWLOntology> downloadOntologies(OWLOntologyManager manager,
   172→      List<URI> configOntologies,
   173→                                                     Path destinationDir) throws OWLOntologyCreationException {
   174→    if (Objects.requireNonNull(configOntologies).isEmpty())
   175→      throw new RuntimeException("No ontologies specified");
   176→    final LinkedHashMap<String, OWLOntology> ontologyByPath = new LinkedHashMap<>();
   177→    for (int i = 0; i < configOntologies.size(); i++) {
   178→      URI ontologyUri = configOntologies.get(i);
   179→      // copy the ontologies used in the destination folder
   180→      String destinationPath = destinationDir + File.separator + "ontology" + i + ".owl";
   181→      File ontologyFile = new File(destinationPath);
   182→      // content negotiation + download in case a URI is added
   183→      String scheme = ontologyUri.getScheme();
   184→      if ("http".equals(scheme) || "https".equals(scheme)) {
   185→        // download ontology to local path
   186→        downloadOntology(ontologyUri, destinationPath);
   187→      } else if (StringUtils.isEmpty(scheme) || "file".equals(scheme)) {
   188→        try {
   189→          // copy to the right folder
   190→          Files.copy(Path.of(ontologyUri.getSchemeSpecificPart()), ontologyFile.toPath(),
   191→              StandardCopyOption.REPLACE_EXISTING);
   192→        } catch (IOException ex) {
   193→          throw new RuntimeException("ERROR while loading file: " + ontologyUri, ex);
   194→        }
   195→      }
   196→
   197→      OWLOntologyLoaderConfiguration loadingConfig = new OWLOntologyLoaderConfiguration();
   198→      loadingConfig = loadingConfig.setMissingImportHandlingStrategy(MissingImportHandlingStrategy.THROW_EXCEPTION)
   199→          .withAllowDuplicatesInConstructSets(true); // required so anonymous classes aren't inlined
   200→      ontologyByPath.put(destinationPath,
   201→          manager.loadOntologyFromOntologyDocument(new FileDocumentSource(new File(destinationPath)), loadingConfig));
   202→    }
