    16→/**
    17→ * Custom deserializer for namespace mappings. Supports deserialization from either a map format
    18→ * (object with arrays or strings) or a single set format (array of strings). Returns a Map\<String,
    19→ * Set\<String\>\> representing the namespace mappings.
    20→ */
    21→public class NamespaceMappingsDeserializer extends JsonDeserializer<Map<String, Set<String>>> {
    22→
    23→  public static final String DEFAULT_NS = "<default>";
    24→
    25→  @Override
    26→  public Map<String, Set<String>> deserialize(JsonParser p, DeserializationContext ctxt)
    27→      throws IOException {
    28→    JsonNode node = p.getCodec().readTree(p);
    29→    Map<String, Set<String>> result = new HashMap<>();
    30→
    31→    if (node.isObject()) {
    32→
    33→      // Map format
    34→      Iterator<Map.Entry<String, JsonNode>> fields = node.fields();
    35→      while (fields.hasNext()) {
    36→        Map.Entry<String, JsonNode> entry = fields.next();
    37→        Set<String> values = new HashSet<>();
    38→        if (entry.getValue().isArray()) {
    39→          for (JsonNode v : entry.getValue()) {
    40→            values.add(v.asText());
    41→          }
    42→        } else {
    43→          values.add(entry.getValue().asText());
    44→        }
    45→        result.put(entry.getKey(), values);
    46→      }
    47→    } else if (node.isArray()) {
    48→      // Single set format
    49→      Set<String> values = new HashSet<>();
    50→      for (JsonNode v : node) {
    51→        values.add(v.asText());
    52→      }
    53→      result.put(DEFAULT_NS, values); // Use a default key or handle as needed
    54→    }
    55→    return result;
    56→  }
    57→
    58→  @Override
    59→  public Map<String, Set<String>> deserialize(JsonParser p, DeserializationContext ctxt,
    60→      Map<String, Set<String>> intoMap)
    61→      throws IOException {
    62→    Map<String, Set<String>> result = deserialize(p, ctxt);
    63→    for (Map.Entry<String, Set<String>> entry : result.entrySet()) {
    64→      intoMap.merge(entry.getKey(), entry.getValue(), (oldSet, newSet) -> {
    65→        oldSet.addAll(newSet);
    66→        return oldSet;
    67→      });
    68→    }
    69→    return intoMap;
    70→  }
